import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped newlines ("\\n") with actual whitespace so tokenisation works
        String processed = raw.toString().replace("\\n", " ");
        Scanner sc = new Scanner(processed);
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) {
            System.out.print("");
            return;
        }
        int T = sc.nextInt();
        while (T-- > 0) {
            if (!sc.hasNextInt()) break;
            int n = sc.nextInt();
            long[] a = new long[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextLong();
            }
            long cand1 = Long.MIN_VALUE, cand2 = Long.MIN_VALUE;
            int cnt1 = 0, cnt2 = 0;
            // First pass: find potential candidates (Boyer-Moore majority vote for n/3)
            for (long x : a) {
                if (cnt1 > 0 && x == cand1) {
                    cnt1++;
                } else if (cnt2 > 0 && x == cand2) {
                    cnt2++;
                } else if (cnt1 == 0) {
                    cand1 = x;
                    cnt1 = 1;
                } else if (cnt2 == 0) {
                    cand2 = x;
                    cnt2 = 1;
                } else {
                    cnt1--;
                    cnt2--;
                }
            }
            // Second pass: verify actual counts
            cnt1 = cnt2 = 0;
            for (long x : a) {
                if (x == cand1) cnt1++;
                else if (x == cand2) cnt2++;
            }
            int limit = n / 3;
            List<Long> ans = new ArrayList<>();
            if (cnt1 > limit) ans.add(cand1);
            if (cnt2 > limit) ans.add(cand2);
            Collections.sort(ans);
            for (int i = 0; i < ans.size(); i++) {
                if (i > 0) out.append(' ');
                out.append(ans.get(i));
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

